import { _decorator, Component, director, Node, Label, Button, ProgressBar } from 'cc';
import { GameManager } from '../Core/GameManager';

const { ccclass, property } = _decorator;

@ccclass('UpgradeScene')
export class UpgradeScene extends Component {
    @property(Button)
    backBtn: Button = null;
    
    @property(Label)
    currentStageLabel: Label = null;
    
    @property(Label)
    nextStageLabel: Label = null;
    
    @property(Label)
    requirementLabel: Label = null;
    
    @property(ProgressBar)
    meritProgress: ProgressBar = null;
    
    @property(Label)
    meritLabel: Label = null;
    
    @property(Button)
    upgradeBtn: Button = null;
    
    private stages = ['clay', 'wood', 'bronze', 'gold'];
    private stageNames = { clay: '泥胎', wood: '木骨', bronze: '铜身', gold: '金身' };
    private stageRequirements = { clay: 100, wood: 500, bronze: 2000, gold: 10000 };
    
    onLoad() {
        this.backBtn.node.on(Button.EventType.CLICK, this.onBack, this);
        this.upgradeBtn.node.on(Button.EventType.CLICK, this.onUpgrade, this);
    }
    
    start() {
        this.updateUI();
    }
    
    updateUI() {
        const player = GameManager.getInstance().playerData;
        const currentStage = player.getStage();
        const currentMerit = player.getCurrency('merit');
        
        this.currentStageLabel.string = `当前阶段：${this.stageNames[currentStage]}`;
        
        const currentIndex = this.stages.indexOf(currentStage);
        if (currentIndex >= this.stages.length - 1) {
            this.nextStageLabel.string = '已达到最高阶段！';
            this.requirementLabel.string = '';
            this.meritProgress.progress = 1;
            this.meritLabel.string = 'MAX';
            this.upgradeBtn.node.active = false;
        } else {
            const nextStage = this.stages[currentIndex + 1];
            const requirement = this.stageRequirements[currentStage];
            
            this.nextStageLabel.string = `下一阶段：${this.stageNames[nextStage]}`;
            this.requirementLabel.string = `需要功德：${requirement}`;
            
            const progress = Math.min(currentMerit / requirement, 1);
            this.meritProgress.progress = progress;
            this.meritLabel.string = `${currentMerit}/${requirement}`;
            
            this.upgradeBtn.node.active = currentMerit >= requirement;
        }
    }
    
    onUpgrade() {
        const player = GameManager.getInstance().playerData;
        const currentStage = player.getStage();
        const requirement = this.stageRequirements[currentStage];
        
        if (player.getCurrency('merit') >= requirement) {
            // 扣除功德
            player.costCurrency('merit', requirement);
            
            // 升级
            const currentIndex = this.stages.indexOf(currentStage);
            const nextStage = this.stages[currentIndex + 1];
            player.setStage(nextStage);
            
            // 升级奖励
            if (nextStage === 'wood') {
                player.addCurrency('incense_sticks', 10);
            } else if (nextStage === 'bronze') {
                player.addCurrency('candles', 10);
            } else if (nextStage === 'gold') {
                player.addCurrency('yuanbao', 100);
            }
            
            this.updateUI();
            // 显示升级成功提示
        }
    }
    
    onBack() {
        director.loadScene('MainScene');
    }
}
